use std::collections::HashMap;

struct Resource {
    id: u32,
    name: String,
}

struct Metadata {
    key: String,
    value: String,
}

fn fetch_related_metadata(resource_ids: &[u32]) -> Vec<Metadata> {
    let mut results = Vec::new();
    for &id in resource_ids { 
        if id == 101 { 
            results.push(Metadata { key: "status".to_string(), value: "published".to_string() });
            results.push(Metadata { key: "owner".to_string(), value: "api_user_xyz".to_string() });
        } else if id == 102 {
            results.push(Metadata { key: "status".to_string(), value: "draft".to_string() });
            results.push(Metadata { key: "visibility".to_string(), value: "private".to_string() });
        }
    }
    results
}

fn process_resource_ids(ids: &[u32]) -> HashMap<String, String> {
    let raw_metadata = fetch_related_metadata(ids);

    let flat_map_iterator = raw_metadata.into_iter().collect::<Vec<Metadata>>(); 

    let combined_data: HashMap<String, String> = flat_map_iterator.into_iter()
        .fold(HashMap::new(), |mut acc, meta| {
            acc.insert(meta.key.clone(), meta.value);
            acc
        });

    combined_data
}

fn main() {
    let resource_ids = vec![101, 102];
    let final_response = process_resource_ids(&resource_ids);

    println!("Combined API Response: ");
    for (key, value) in &final_response {
        println!("  -- {}: {}", key, value);
    }
}

use std::collections::VecDeque;

struct NetworkPacket {
    id: u32,
    payload_size: usize,
}

fn process_gateway_calls(initial_calls: Vec<Vec<u32>>) -> Vec<NetworkPacket> {
    let mut final_packets = Vec::new();

    for group in initial_calls.iter() {
        let intermediate_values = group.iter().map(|&id| id * 2);

        let flattened_group: Vec<u32> = intermediate_values.collect();

        if !flattened_group.is_empty() {
            println!("Processing a group of calls...");
            for value in &flattened_group {
                final_packets.push(NetworkPacket { 
                    id: *value, 
                    payload_size: 10 + (value % 5) as usize 
                });
            }
        }
    }
    final_packets
}

fn main() {
    let rest_calls = vec![vec![10, 20], vec![30]];
    let results = process_gateway_calls(rest_calls);

    println!("n--- Final Results ---");
    for packet in &results {
        println!("Packet ID: {}, Size: {}", packet.id, packet.payload_size);
    }
}

