use std::collections::HashSet;
use std::error::Error;

struct ProjectGraph {
    dependencies: Vec<Vec<String>>
}

impl ProjectGraph {
    fn new(deps: Vec<Vec<String>>) -> Self {
        ProjectGraph { dependencies: deps }
    }

    fn collect_all_dependencies(&self) -> Result<HashSet<String>, Box<dyn Error>> {
        let mut result = HashSet::new();

        for dependency_list in &self.dependencies {
            for path in dependency_list {
                result.insert(path.clone());
            }
        }

        Ok(result)
    }
}

use std::collections::HashMap;

#[derive(Debug)]
struct Post {
    user_id: u32,
    content: String,
}

fn get_posts_for_user(user_id: u32) -> Vec<Post> {
    if user_id == 101 {
        vec![ 
            Post { user_id: 101, content: "First post".to_string() },
            Post { user_id: 101, content: "Second post".to_string() },
        ]
    } else if user_id == 202 {
        vec![ 
            Post { user_id: 202, content: "User two's entry".to_string() },
        ]
    } else {
        vec![]
    }
}

fn batch_load_posts(user_ids: Vec<u32>) -> Vec<Post> {
    let mut all_posts = Vec::new();
    for id in user_ids {
        let posts = get_posts_for_user(id);
        all_posts.extend(posts);
    }
    all_posts
}

fn main() {
    let ids_to_process = vec![101, 202];
    let results = batch_load_posts(ids_to_process);
    println!("Total posts loaded: {}", results.len());
    for post in results {
        println!("  - User {}: {}", post.user_id, post.content); 
    }
}
